import { Check, X, Scissors } from "lucide-react";
import { SERVICES } from "..";

export default function FormPanel({ form, setForm, editing, onSubmit, onCancel }) {
  const handleChange = (field) => (e) =>
    setForm((prev) => ({ ...prev, [field]: e.target.value }));

  return (
    <aside className="pb-sidebar">
      <p className="pb-section-label">
        <Scissors size={10} />
        Formulário
      </p>

      <h2 className="pb-form-title">
        {editing ? (
          <>
            Editar
            <span className="edit-badge">editando</span>
          </>
        ) : (
          "Novo Agendamento"
        )}
      </h2>

      <div className="pb-field">
        <label className="pb-label">Nome do Cliente</label>
        <input
          className="pb-input"
          placeholder="Ex: João Silva"
          value={form.name}
          onChange={handleChange("name")}
        />
      </div>

      <div className="pb-field">
        <label className="pb-label">Serviço</label>
        <select
          className="pb-select"
          value={form.service}
          onChange={handleChange("service")}
        >
          <option value="">Selecione um serviço</option>
          {SERVICES.map((s) => (
            <option key={s} value={s}>{s}</option>
          ))}
        </select>
      </div>

      <div className="pb-field">
        <label className="pb-label">Data &amp; Hora</label>
        <div className="pb-date-row">
          <input
            className="pb-input"
            type="date"
            value={form.date}
            onChange={handleChange("date")}
          />
          <input
            className="pb-input"
            type="time"
            value={form.time}
            onChange={handleChange("time")}
          />
        </div>
      </div>

      <button
        className={`pb-btn-primary${editing ? " edit" : ""}`}
        onClick={onSubmit}
      >
        {editing && <Check size={15} />}
        {editing ? "Salvar Alterações" : "Confirmar Agendamento"}
      </button>

      {editing && (
        <button className="pb-btn-cancel" onClick={onCancel}>
          <X size={12} style={{ marginRight: 6 }} />
          Cancelar edição
        </button>
      )}
    </aside>
  );
}
